mapper.select:
select a.* from lkt_record as a left join lkt_user as c on c.user_id = a.user_id
order by a.add_date desc
LIMIT #{pageStart},#{pageEnd}

select a.id,a.user_id, c.user_name, c.mobile, c.source,c.zhanghao, c.Register_data,a.event,a.add_date,a.type as recordType, a.money,d.type, a.details_id,d.money_type as moneyType,d.record_notes as remake,d.exchange_rate,d.currency_code,d.currency_symbol, CASE c.source WHEN 1 THEN '小程序' WHEN 2 THEN 'H5移动端' WHEN 3 THEN '支付宝小程序' WHEN 4 THEN '头条小程序' WHEN 5 THEN '百度小程序' WHEN 6 THEN 'PC端' WHEN 11 THEN 'APP端' ELSE '未知' END as sourceName, CASE a.type WHEN 1 THEN '用户充值' WHEN 11 THEN '系统扣款' WHEN 14 THEN '系统充值' WHEN 4 THEN '余额消费' when 42 then '直播佣金转入' ELSE '未知' END as typeName from lkt_record as a left join lkt_user as c on c.user_id = a.user_id left join lkt_record_details d on a.details_id = d.id
order by a.add_date desc
LIMIT #{pageStart},#{pageEnd}

select a.id, c.user_id, a.type, c.user_name,a.add_date as `addtime`,a.money,c.Register_data, CASE a.type WHEN 1 THEN '用户充值' WHEN 2 THEN '申请提现' WHEN 4 THEN '余额消费' WHEN 5 THEN '退款' WHEN 11 THEN '系统扣除' WHEN 14 THEN '系统充值' WHEN 22 THEN '提现失败' WHEN 28 THEN '售后退款' WHEN 26 THEN '缴纳押金' WHEN 27 THEN '退竞拍押金' WHEN 31 THEN '充值会员' WHEN 32 THEN '购物消费' WHEN 33 THEN '押金退回' WHEN 34 THEN '缴纳押金' WHEN 36 THEN '线上消费' WHEN 37 THEN '第三方退款' WHEN 38 THEN '缴纳店铺押金' WHEN 39 THEN '退店铺押金' when 42 then '直播佣金转入' ELSE '-' END AS typeName, CASE a.type WHEN 1 THEN '入账' WHEN 2 THEN '出账' WHEN 4 THEN '出账' WHEN 5 THEN '入账' WHEN 11 THEN '出账' WHEN 14 THEN '入账' WHEN 22 THEN '入账' WHEN 28 THEN '入账' WHEN 26 THEN '出账' WHEN 27 THEN '入账' WHEN 31 THEN '出账' WHEN 32 THEN '出账' WHEN 33 THEN '入账' WHEN 34 THEN '缴纳押金' WHEN 36 THEN '出账' WHEN 37 THEN '入账' WHEN 38 THEN '出账' WHEN 39 THEN '入账' ELSE '-' END AS statusName from lkt_record as a left join lkt_user as c on c.user_id = a.user_id
order by a.add_date desc
LIMIT #{pageStart},#{pageEnd}

select a.*,c.user_name,c.mobile,c.source from lkt_sign_record as a left join lkt_user as c on c.user_id = a.user_id
order by a.sign_time desc
LIMIT #{pageStart},#{pageEnd}
